import React, { useEffect, useState } from 'react';
import { Box, Typography, LinearProgress, keyframes } from '@mui/material';

const SPLASH_MS = Number(process.env.REACT_APP_SPLASH_DURATION_MS) || 10000;

/** Brand blues + subtle depth (includes black channel per spec) */
const BG_GRADIENT = `
  linear-gradient(165deg,
    #2596be 0%,
    rgb(37, 150, 190) 45%,
    rgba(0, 0, 0, 0.28) 100%
  )
`;

const goldShimmer = keyframes`
  0% { box-shadow: 0 0 0 0 rgba(212, 175, 55, 0.4), 0 8px 32px rgba(0, 0, 0, 0.15); }
  50% { box-shadow: 0 0 22px 2px rgba(212, 175, 55, 0.35), 0 12px 40px rgba(0, 0, 0, 0.12); }
  100% { box-shadow: 0 0 0 0 rgba(212, 175, 55, 0.4), 0 8px 32px rgba(0, 0, 0, 0.15); }
`;

function SplashScreen({ durationMs = SPLASH_MS }) {
  const [progress, setProgress] = useState(0);
  const [secondsLeft, setSecondsLeft] = useState(Math.ceil(durationMs / 1000));

  useEffect(() => {
    const start = performance.now();
    let frame;

    const tick = (now) => {
      const elapsed = now - start;
      const pct = Math.min(100, (elapsed / durationMs) * 100);
      setProgress(pct);
      setSecondsLeft(Math.max(0, Math.ceil((durationMs - elapsed) / 1000)));
      if (elapsed < durationMs) {
        frame = requestAnimationFrame(tick);
      } else {
        setProgress(100);
        setSecondsLeft(0);
      }
    };

    frame = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frame);
  }, [durationMs]);

  return (
    <Box
      sx={{
        position: 'relative',
        minHeight: '100vh',
        width: '100%',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        background: BG_GRADIENT,
        backgroundColor: '#2596be',
        overflow: 'hidden',
      }}
    >
      {/* Subtle vignette for corporate depth */}
      <Box
        sx={{
          position: 'absolute',
          inset: 0,
          pointerEvents: 'none',
          background: 'radial-gradient(ellipse 80% 70% at 50% 40%, transparent 0%, rgba(0,0,0,0.12) 100%)',
        }}
      />

      <Box sx={{ position: 'relative', zIndex: 1, textAlign: 'center', px: 3, maxWidth: 420 }}>
        {/* Rounded square: gold ring, transparent center, “S” */}
        <Box
          sx={{
            width: { xs: 112, sm: 128 },
            height: { xs: 112, sm: 128 },
            mx: 'auto',
            mb: 3,
            borderRadius: '28px',
            border: '3px solid #d4af37',
            background: 'rgba(255, 255, 255, 0.06)',
            backdropFilter: 'blur(10px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            animation: `${goldShimmer} 3.5s ease-in-out infinite`,
          }}
        >
          <Typography
            component="span"
            sx={{
              fontSize: { xs: '4rem', sm: '4.5rem' },
              fontWeight: 800,
              lineHeight: 1,
              color: 'rgba(255, 255, 255, 0.88)',
              WebkitTextStroke: '1px rgba(255, 255, 255, 0.35)',
              textShadow: '0 2px 20px rgba(255,255,255,0.2)',
            }}
          >
            S
          </Typography>
        </Box>

        <Typography
          sx={{
            color: '#ffffff',
            fontWeight: 800,
            fontSize: { xs: '2rem', sm: '2.75rem' },
            letterSpacing: '0.06em',
            textShadow: '0 4px 20px rgba(0, 0, 0, 0.2)',
            mb: 1,
          }}
        >
          StitchyFlow
        </Typography>

        <Typography
          sx={{
            color: 'rgba(255, 255, 255, 0.95)',
            fontWeight: 500,
            fontSize: { xs: '0.95rem', sm: '1.05rem' },
            letterSpacing: '0.04em',
            mb: 4,
            lineHeight: 1.45,
          }}
        >
          Just Click to Tailoring Services
        </Typography>

        {/* Solid (non-transparent) loading bar — linear 10s fill */}
        <Box sx={{ width: '100%', maxWidth: 320, mx: 'auto' }}>
          <LinearProgress
            variant="determinate"
            value={progress}
            sx={{
              height: 6,
              borderRadius: 3,
              bgcolor: 'rgba(255, 255, 255, 0.25)',
              '& .MuiLinearProgress-bar': {
                borderRadius: 3,
                background: 'linear-gradient(90deg, #ffffff 0%, #e8f4fc 50%, #ffffff 100%)',
              },
            }}
          />
          <Typography
            sx={{
              mt: 1.5,
              color: '#ffffff',
              fontWeight: 600,
              fontSize: '0.8rem',
              letterSpacing: '0.12em',
              textTransform: 'uppercase',
            }}
          >
            Loading… {secondsLeft > 0 ? `${secondsLeft}s` : '0s'}
          </Typography>
        </Box>
      </Box>

      <Typography
        variant="caption"
        sx={{
          position: 'absolute',
          bottom: 28,
          left: 0,
          right: 0,
          textAlign: 'center',
          color: 'rgba(255, 255, 255, 0.72)',
          fontSize: '0.75rem',
          letterSpacing: '0.02em',
        }}
      >
        Powered by LogixInventor (PVT) Ltd.
      </Typography>
    </Box>
  );
}

export default SplashScreen;
export { SPLASH_MS };
